# Problem: Implement defensive type conversion functions that never raise exceptions.
# Messy input data causes ValueError/TypeError crashes — we need safe wrappers.
#
# Approach:
#   - safe_int/safe_float: wrap int()/float() in try/except for ValueError and TypeError
#   - parse_value: strip whitespace, then try conversions in order: bool > int > float > str
#   - safe_list: simple type checks with if/elif chain
#
# Time complexity: O(1) for all functions (constant-time conversions)
# Space complexity: O(1)
#
# Key steps:
#   1. safe_int/safe_float: try conversion, return default on failure
#   2. parse_value: strip input, check lowercase for bool literals, then try int, float
#   3. safe_list: check None, then list, then wrap in list

def safe_int(value, default=0):
    try:
        return int(value)
    except (ValueError, TypeError):
        return default


def safe_float(value, default=0.0):
    try:
        return float(value)
    except (ValueError, TypeError):
        return default


def parse_value(s: str):
    stripped = s.strip()
    # Check bool first (case-insensitive)
    if stripped.lower() == 'true':
        return True
    if stripped.lower() == 'false':
        return False
    # Try int before float so '42' returns int, not float
    try:
        return int(stripped)
    except ValueError:
        pass
    try:
        return float(stripped)
    except ValueError:
        pass
    # Fall back to stripped string
    return stripped


def safe_list(value):
    if value is None:
        return []
    if isinstance(value, list):
        return value
    return [value]
